let{test,expect}=require("@playwright/test"),config={languages:[{code:"en",name:"English",dir:"ltr",default:!0},{code:"es",name:"Español",dir:"ltr"},{code:"fr",name:"Français",dir:"ltr"},{code:"ar",name:"العربية",dir:"rtl"}],baseUrl:"http://localhost:8001"};test("Content should change when clicking the Spanish debug button",async({page:t})=>{await t.goto(config.baseUrl),await t.waitForSelector(".signup-button");var e=await t.textContent(".signup-button"),t=(console.log("English Sign Up text:",e),await t.click('button:has-text("Go to Spanish Version")'),await t.waitForTimeout(1e3),await t.textContent(".signup-button"));console.log("Spanish Sign Up text:",t),expect(t).not.toBe(e),expect(t).toBe("Registrarse")}),test("Content should change on the translation test page",async({page:t})=>{await t.goto(config.baseUrl+"/translation-test.html"),await t.waitForSelector('[data-i18n="buttons.signUp"]');var e=await t.textContent('[data-i18n="buttons.signUp"]'),a=(console.log("Initial Sign Up text:",e),await t.click('button:has-text("Español")'),await t.waitForTimeout(1e3),await t.textContent('[data-i18n="buttons.signUp"]')),e=(console.log("Spanish Sign Up text:",a),expect(a).not.toBe(e),expect(a).toBe("Registrarse"),await t.evaluate(()=>document.documentElement.lang));expect(e).toBe("es")});